+/// Row-major n×n matmul for two flat square matrices. Used by linalg
+/// metamorphic relations that verify A · inv(A) == I.
+fn square_matmul_flat(a: &[f64], b: &[f64], n: usize) -> Vec<f64> {
+    let mut result = vec![0.0_f64; n * n];
+    for i in 0..n {
+        for j in 0..n {
+            let mut sum = 0.0;
+            for k in 0..n {
+                sum += a[i * n + k] * b[k * n + j];
+            }
+            result[i * n + j] = sum;
+        }
+    }
+    result
+}
